// buildIngestMetadata constructs integration ingest metadata from operation context and options
func buildIngestMetadata(integration *ent.Integration, operationName string, record mappedIngestRecord, options IngestOptions) integrationgenerated.IntegrationIngestMetadata {
	source := options.Source
	if source == "" {
		source = integrationgenerated.IntegrationIngestSourceDirect
	}

	metadata := integrationgenerated.IntegrationIngestMetadata{
		IntegrationID: integration.ID,
		DefinitionID:  integration.DefinitionID,
		Source:        source,
		Operation:     operationName,
		Variant:       record.Variant,
		RunID:         options.RunID,
		Webhook:       options.Webhook,
		WebhookEvent:  options.WebhookEvent,
		DeliveryID:    options.DeliveryID,
	}

	if options.WorkflowMeta != nil {
		metadata.WorkflowInstanceID = options.WorkflowMeta.InstanceID
		metadata.WorkflowActionKey = options.WorkflowMeta.ActionKey
		metadata.WorkflowActionIndex = options.WorkflowMeta.ActionIndex
		metadata.WorkflowObjectID = options.WorkflowMeta.ObjectID
		metadata.WorkflowObjectType = string(options.WorkflowMeta.ObjectType)
	}

	return metadata
}

// buildIngestHeaders assembles Gala message headers for one ingest record
func buildIngestHeaders(record mappedIngestRecord, metadata integrationgenerated.IntegrationIngestMetadata) gala.Headers {
	tags := []string{metadata.DefinitionID, "schema_" + strings.ToLower(record.Schema)}
	if metadata.Source != "" {
		tags = append(tags, string(metadata.Source))
	}

	return gala.Headers{
		Properties: lo.PickBy(map[string]string{
			"schema":               record.Schema,
			"integration_id":       metadata.IntegrationID,
			"definition_id":        metadata.DefinitionID,
			"operation":            metadata.Operation,
			"variant":              record.Variant,
			"run_id":               metadata.RunID,
			"webhook":              metadata.Webhook,
			"webhook_event":        metadata.WebhookEvent,
			"delivery_id":          metadata.DeliveryID,
			"workflow_instance_id": metadata.WorkflowInstanceID,
			"workflow_action_key":  metadata.WorkflowActionKey,
		}, func(_ string, value string) bool {
			return value != ""
		}),
		Tags: tags,
	}
}

